        perror("write failed");
        return -1;
    }

    if (read(file, buf, 2) != 2) {
        perror("read failed");
        return -1;
    }

    reg = (buf[0] << 8) | buf[1];

    // Convert raw value to degrees Celsius
    float temp = (reg >> 4) * 0.0625;

    return temp;
}

