        if (raw_data_low < 0) {
            fprintf(stderr, "Error reading sensor on CE0\n");
        } else {
            temperature_low = convert_to_celsius(raw_data_low);
            printf("Sensor CE0 Temperature: %.2f C\n", temperature_low);
        }

        raw_data_high = read_max31855(SPI_CE1);
        if (raw_data_high < 0) {
            fprintf(stderr, "Error reading sensor on CE1\n");
        } else {
            temperature_high = convert_to_celsius(raw_data_high);
            printf("Sensor CE1 Temperature: %.2f C\n", temperature_high);
        }

        // Determine the average temperature
        float average_temperature;
        if (raw_data_low >= 0 && raw_data_high >= 0) {
            average_temperature = (temperature_low + temperature_high) / 2.0;
        } else {
            // If one or both sensors failed, use only the valid sensor's data.
            // If both failed, use a default temperature (e.g., 50°C).
            average_temperature = (raw_data_low >= 0) ? temperature_low : 50.0; // Default temperature
        }

        // Control fan speed based on average temperature
        int fan_speed;
        if (average_temperature < TEMP_LOW) {
