            // Debounce the button
            while (digitalRead(BUTTON_GPIO) == PI_GPIO_LOW) {
                sleep(0.01); // Wait 10ms
            }
            // Button has been released
            printf("Button pressed\n");

            // Toggle the locks
            int state = digitalRead(LOCK_1_GPIO);
            digitalWrite(LOCK_1_GPIO, !state);
            state = digitalRead(LOCK_2_GPIO);
            digitalWrite(LOCK_2_GPIO, !state);

            // Log the event
            logEvent("Lock toggled, Lock 1: %d, Lock 2: %d", !state, !state);
        }
    }

    // This point should never be reached due to the infinite loop
    closeGPIO();
    return 0;
}

