// Constants
#define PIR_GPIO 4
#define I2C_BUS 1
#define SI1153_ADDR 0x60

// Si1153 Registers
#define SI1153_REG_ALS_VIS_DATA0 0x10
#define SI1153_REG_ALS_IR_DATA0 0x12
#define SI1153_REG_UV_INDEX0 0x2C
#define SI1153_REG_PROX_DATA0 0x24

int i2c_handle;
volatile sig_atomic_t program_running = 1;

// Function prototypes
int readProximity(int handle);
int readALS(int handle);
int readUVIndex(int handle);
void signal_handler(int signal);

/**
 * @brief Reads the proximity value from the Si1153 sensor.
 *
 * @param handle The I2C handle.
 * @return The proximity value, or -1 on error.
 */
int readProximity(int handle) {
    int proximity = i2cReadByteData(handle, SI1153_REG_PROX_DATA0);
    if (proximity < 0) {
        fprintf(stderr, "Error reading proximity data: %d\n", proximity);
        return -1;
    }
    return proximity;
}

/**
 * @brief Reads the ambient light sensor value from the Si1153 sensor.
 *
 * @param handle The I2C handle.
 * @return The ALS value, or -1 on error.
 */
int readALS(int handle) {
    int als_vis_low = i2cReadByteData(handle, SI1153_REG_ALS_VIS_DATA0);
    int als_vis_high = i2cReadByteData(handle, SI1153_REG_ALS_VIS_DATA0 + 1);
    if (als_vis_low < 0 || als_vis_high < 0) {
        fprintf(stderr, "Error reading ALS data: low=%d, high=%d\n", als_vis_low, als_vis_high);
        return -1;
    }

    int als = (als_vis_high << 8) | als_vis_low;
    return als;
}

/**
 * @brief Reads the UV index from the Si1153 sensor.
 *
 * @param handle The I2C handle.
 * @return The UV index, or -1 on error.
 */
int readUVIndex(int handle) {
    int uv_index = i2cReadByteData(handle, SI1153_REG_UV_INDEX0);
    if (uv_index < 0) {
        fprintf(stderr, "Error reading UV index: %d\n", uv_index);
        return -1;
    }
    return uv_index;
}

void signal_handler(int signal) {
    program_running = 0;
    printf("Caught signal %d, exiting gracefully...\n", signal);
}

