    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure PIR sensor GPIO as input
    gpioSetMode(PIR_GPIO, PI_INPUT);

    // Open I2C connection
    i2c_handle = i2cOpen(I2C_BUS, SI1153_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Motion-triggered sensor logging started. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Read PIR sensor
        int motion_detected = gpioRead(PIR_GPIO);

        if (motion_detected == 1) {
