        exit(EXIT_FAILURE);
    }

    // Initialize Si1153
    if (!si1153_init(fd)) {
        perror("Failed to initialize Si1153");
        exit(EXIT_FAILURE);
    }

    // Open log file
    FILE *log_file = fopen(FILENAME, "a");
