void log_lux(int lux) {
    FILE *file;
    time_t t;
    struct tm *tm_info;

    time(&t);
    tm_info = localtime(&t);

    file = fopen("light_log.txt", "a");
    if (file == NULL) {
        perror("Error opening file");
        return;
    }

    fprintf(file, "%04d-%02d-%02d %02d:%02d:%02d: Lux: %d\n", 
            tm_info->tm_year + 1900, tm_info->tm_mon + 1, tm_info->tm_mday,
            tm_info->tm_hour, tm_info->tm_min, tm_info->tm_sec, lux);
    fclose(file);
}

int main() {
    int gpio, status, i2c_id, lux;
    char buffer[8];

    // Initialize pigpio
    if ((status = gpioInitialise()) < 0) {
        fprintf(stderr, "pigpio initialization failed: %s\n", pigpioGetError(status));
        return 1;
    }

    // Set up the LED GPIO
    gpio = 24;
    gpioSetMode(gpio, PI_OUTPUT);
    gpioPWM(gpio, 0);  // Turn off the LED

    // Initialize I2C
    i2c_id = i2cOpen(1, BH1750_ADDRESS, 0);
    if (i2c_id < 0) {
        fprintf(stderr, "I2C open failed: %s\n", pigpioGetError(i2c_id));
        return 1;
    }

    while (1) {
        // Start measurement
        i2cWriteReg(i2c_id, BH1750_CMD_MEASUREMENT, 0);

        // Wait for measurement to complete
        gpioDelay(150);

        // Read the result
        i2cReadReg(i2c_id, 0x10, 2, buffer);
        lux = (buffer[0] << 8) | buffer[1];
        lux /= 1.2;

        // Adjust LED brightness
        gpioPWM(gpio, lux);

        // Log significant changes
        if (last_lux != -1 && abs(lux - last_lux) >= 5) {
            log_lux(lux);
            last_lux = lux;
        }

        // Small delay to avoid flooding
        gpioDelay(200);
    }

    // Cleanup
    gpioTerminate();
    i2cClose(i2c_id);

    return 0;
}

